import { useState, useCallback } from "react";
import { useQueryClient } from "@tanstack/react-query";
import { useNotify, useRefresh, useDataProvider } from "ra-core";
import { logger } from "@/lib/logger";
import type { Opportunity, OpportunityStageValue } from "../types";
import { opportunityKeys, entityTimelineKeys } from "@/atomic-crm/queryKeys";

export type BulkAction = "change_stage" | "change_status" | "assign_owner" | "archive" | null;

export interface UseBulkActionsStateOptions {
  selectedIds: (string | number)[];
  opportunities: Opportunity[];
  onUnselectItems: () => void;
  resource?: string;
}

export interface UseBulkActionsStateResult {
  activeAction: BulkAction;
  setActiveAction: (action: BulkAction) => void;

  selectedStage: string;
  setSelectedStage: (stage: string) => void;
  selectedStatus: string;
  setSelectedStatus: (status: string) => void;
  selectedOwner: string;
  setSelectedOwner: (owner: string) => void;
  assignField: "primary" | "secondary";
  setAssignField: (field: "primary" | "secondary") => void;

  isProcessing: boolean;

  handleOpenDialog: (action: BulkAction) => void;
  handleCloseDialog: () => void;
  handleExecuteBulkAction: () => Promise<void>;
  handleBulkArchive: () => Promise<void>;
  canExecute: () => boolean;
}

export function useBulkActionsState({
  selectedIds,
  opportunities,
  onUnselectItems,
  resource = "opportunities",
}: UseBulkActionsStateOptions): UseBulkActionsStateResult {
  const [activeAction, setActiveAction] = useState<BulkAction>(null);
  const [selectedStage, setSelectedStage] = useState<string>("");
  const [selectedStatus, setSelectedStatus] = useState<string>("");
  const [selectedOwner, setSelectedOwner] = useState<string>("");
  const [assignField, setAssignField] = useState<"primary" | "secondary">("primary");
  const [isProcessing, setIsProcessing] = useState(false);

  const notify = useNotify();
  const refresh = useRefresh();
  const dataProvider = useDataProvider();
  const queryClient = useQueryClient();

  const handleOpenDialog = useCallback((action: BulkAction) => {
    setActiveAction(action);
    setSelectedStage("");
    setSelectedStatus("");
    setSelectedOwner("");
    setAssignField("primary");
  }, []);

  const handleCloseDialog = useCallback(() => {
    setActiveAction(null);
    setSelectedStage("");
    setSelectedStatus("");
    setSelectedOwner("");
    setAssignField("primary");
  }, []);

  const handleExecuteBulkAction = useCallback(async () => {
    if (!activeAction) return;

    setIsProcessing(true);
    let successCount = 0;
    let failureCount = 0;
    let skippedCount = 0;

    try {
      let updateData: Partial<Opportunity> = {};

      if (activeAction === "change_stage" && selectedStage) {
        updateData = { stage: selectedStage as OpportunityStageValue, stage_manual: true };
      } else if (activeAction === "change_status" && selectedStatus) {
        updateData = { status: selectedStatus as Opportunity["status"], stage_manual: true };
      } else if (activeAction === "assign_owner" && selectedOwner) {
        const field = assignField === "primary" ? "opportunity_owner_id" : "account_manager_id";
        updateData = { [field]: parseInt(selectedOwner) } as Partial<Opportunity>;
      }

      const resolvedItems = selectedIds
        .map((id) => ({ id, previous: opportunities.find((opp) => opp.id === id) }))
        .filter((item): item is { id: (typeof selectedIds)[number]; previous: Opportunity } => {
          if (!item.previous) {
            logger.debug("Skipped update: record not in local data", {
              id: String(item.id),
              feature: "BulkActions",
            });
            skippedCount++;
            return false;
          }
          return true;
        });

      const updatePromises = resolvedItems.map(({ id, previous }) =>
        dataProvider.update(resource, {
          id,
          data: updateData,
          previousData: previous,
        })
      );

      const results = await Promise.allSettled(updatePromises);

      results.forEach((result, index) => {
        if (result.status === "fulfilled") {
          successCount++;
        } else {
          logger.error("Bulk update failed", result.reason, {
            feature: "useBulkActionsState",
            resource,
            id: resolvedItems[index].id,
          });
          failureCount++;
        }
      });

      // NOTE: Activity logging removed - DB trigger handles stage change logging

      if (successCount > 0) {
        const skippedSuffix = skippedCount > 0 ? ` (${skippedCount} skipped)` : "";
        notify(
          `Successfully updated ${successCount} opportunit${successCount === 1 ? "y" : "ies"}${skippedSuffix}`,
          {
            type: skippedCount > 0 ? "warning" : "success",
          }
        );
      }
      if (failureCount > 0) {
        notify(`Failed to update ${failureCount} opportunit${failureCount === 1 ? "y" : "ies"}`, {
          type: "error",
        });
      }

      queryClient.invalidateQueries({ queryKey: opportunityKeys.lists() });
      queryClient.invalidateQueries({ queryKey: entityTimelineKeys.lists() });
      refresh();
      onUnselectItems();
      handleCloseDialog();
    } catch (error: unknown) {
      notify("Bulk action failed", { type: "error" });
      logger.error("Bulk action error", error, { feature: "useBulkActionsState" });
    } finally {
      setIsProcessing(false);
    }
  }, [
    activeAction,
    selectedStage,
    selectedStatus,
    selectedOwner,
    assignField,
    selectedIds,
    resource,
    dataProvider,
    opportunities,
    notify,
    queryClient,
    refresh,
    onUnselectItems,
    handleCloseDialog,
  ]);

  const handleBulkArchive = useCallback(async () => {
    setIsProcessing(true);

    try {
      await dataProvider.deleteMany(resource, { ids: selectedIds });

      // Create activity records for successful bulk archive
      if (selectedIds.length > 0) {
        const activityPromises = selectedIds.map(async (id) => {
          const opportunity = opportunities.find((opp) => opp.id === id);
          if (!opportunity) return;

          try {
            await dataProvider.create("activities", {
              data: {
                activity_type: "activity",
                type: "note",
                subject: "Opportunity archived (bulk update)",
                activity_date: new Date().toISOString(),
                opportunity_id: id,
                organization_id: opportunity.customer_organization_id,
              },
            });
          } catch (error: unknown) {
            logger.warn("Activity logging failed for bulk archive", {
              feature: "useBulkActionsState",
              opportunityId: id,
              error: error instanceof Error ? error.message : String(error),
            });
            // Don't block the archive if activity logging fails
          }
        });

        // Fire-and-forget activity creation (don't block UI)
        void Promise.allSettled(activityPromises);
      }

      notify(
        `Successfully archived ${selectedIds.length} opportunit${selectedIds.length === 1 ? "y" : "ies"}`,
        { type: "success" }
      );

      queryClient.invalidateQueries({ queryKey: opportunityKeys.lists() });
      queryClient.invalidateQueries({ queryKey: entityTimelineKeys.lists() });
      refresh();
      onUnselectItems();
      handleCloseDialog();
    } catch (error: unknown) {
      notify(
        `Failed to archive opportunities: ${error instanceof Error ? error.message : "Unknown error"}`,
        { type: "error" }
      );
    } finally {
      setIsProcessing(false);
    }
  }, [
    selectedIds,
    resource,
    dataProvider,
    opportunities,
    notify,
    queryClient,
    refresh,
    onUnselectItems,
    handleCloseDialog,
  ]);

  const canExecute = useCallback(() => {
    if (activeAction === "change_stage") return !!selectedStage;
    if (activeAction === "change_status") return !!selectedStatus;
    if (activeAction === "assign_owner") return !!selectedOwner;
    return false;
  }, [activeAction, selectedStage, selectedStatus, selectedOwner]);

  return {
    activeAction,
    setActiveAction,
    selectedStage,
    setSelectedStage,
    selectedStatus,
    setSelectedStatus,
    selectedOwner,
    setSelectedOwner,
    assignField,
    setAssignField,
    isProcessing,
    handleOpenDialog,
    handleCloseDialog,
    handleExecuteBulkAction,
    handleBulkArchive,
    canExecute,
  };
}
