import * as React from "react";
import { AdminButton } from "@/components/admin/AdminButton";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Building2,
  Flag,
  Layers,
  Megaphone,
  User,
  Calendar,
  AlertCircle,
  Trophy,
} from "lucide-react";
import { useGetIdentity, useGetList, useListContext } from "ra-core";
import { addDays } from "date-fns";

import { ToggleFilterButton } from "@/components/ra-wrappers/toggle-filter-button";
import { FilterCategory } from "../filters/FilterCategory";
import { FilterSidebar } from "../filters/FilterSidebar";
import { QuickFilterGroup } from "../filters/QuickFilterGroup";
import { usePresetFilter } from "../filters/usePresetFilter";
import { OPPORTUNITY_STAGES, STAGE, priorityChoices } from "./constants";
import { OwnerFilterDropdown } from "@/components/ra-wrappers/OwnerFilterDropdown";
import { DEFAULT_PAGE_SIZE } from "@/atomic-crm/constants/appConstants";

export const OpportunityListFilter = () => {
  const { data: identity } = useGetIdentity();
  const { filterValues, setFilters } = useListContext();
  const { isPresetActive, handlePresetClick } = usePresetFilter();

  // PERF: Fetch all relevant organizations in a single query instead of two sequential calls
  // Previously: 2 separate useGetList calls (principals + customers) = 2 network requests
  // Now: 1 combined query + client-side filtering = 1 network request
  const { data: organizationsData } = useGetList("organizations", {
    pagination: { page: 1, perPage: DEFAULT_PAGE_SIZE },
    sort: { field: "name", order: "ASC" },
    filter: {
      "organization_type@in": "(principal,prospect,customer)",
      deleted_at: null,
    },
  });

  // Split organizations client-side to maintain same data shape for consuming components
  const principalsData = React.useMemo(
    () => organizationsData?.filter((org) => org.organization_type === "principal") ?? [],
    [organizationsData]
  );

  const customersData = React.useMemo(
    () =>
      organizationsData?.filter(
        (org) => org.organization_type === "prospect" || org.organization_type === "customer"
      ) ?? [],
    [organizationsData]
  );

  // Handle principal filter change via Select dropdown
  const handlePrincipalChange = (value: string) => {
    if (value === "all") {
      // SAFETY WARNING: UI-ONLY PATTERN
      // This destructuring drops keys (principal_organization_id).
      // DO NOT use this pattern in Data Providers or Services where data loss could persist to DB.
      const { principal_organization_id: _, ...rest } = filterValues || {};
      setFilters(rest);
    } else {
      setFilters({
        ...filterValues,
        principal_organization_id: Number(value),
      });
    }
  };

  // Handle customer filter change via Select dropdown
  const handleCustomerChange = (value: string) => {
    if (value === "all") {
      const { customer_organization_id: _, ...rest } = filterValues || {};
      setFilters(rest);
    } else {
      setFilters({
        ...filterValues,
        customer_organization_id: Number(value),
      });
    }
  };

  // Handle campaign filter change via Select dropdown
  const handleCampaignChange = (value: string) => {
    if (value === "all") {
      const { campaign: _, ...rest } = filterValues || {};
      setFilters(rest);
    } else {
      setFilters({
        ...filterValues,
        campaign: value,
      });
    }
  };

  // Get current filter values for controlled Selects
  const currentPrincipalFilter = filterValues?.principal_organization_id
    ? String(filterValues.principal_organization_id)
    : "all";

  const currentCustomerFilter = filterValues?.customer_organization_id
    ? String(filterValues.customer_organization_id)
    : "all";

  const currentCampaignFilter = filterValues?.campaign || "all";

  // Fetch distinct campaign values efficiently via database view
  // P0-PERF-1 fix: Previously fetched 1000 full records, now fetches only unique values
  const { data: campaignsData } = useGetList<{ id: string; name: string }>(
    "distinct_opportunities_campaigns",
    {
      pagination: { page: 1, perPage: DEFAULT_PAGE_SIZE },
      sort: { field: "name", order: "ASC" },
    },
    {
      staleTime: 5 * 60 * 1000, // Cache for 5 minutes
      gcTime: 15 * 60 * 1000,
      refetchOnWindowFocus: false,
    }
  );

  const campaigns = React.useMemo(() => campaignsData?.map((c) => c.name) ?? [], [campaignsData]);

  // Quick filter presets
  const today = new Date();
  const thirtyDaysFromNow = addDays(today, 30);

  return (
    <FilterSidebar showSearch={false}>
      {/* Quick Filter Presets */}
      <QuickFilterGroup label="Quick Filters">
        <AdminButton
          type="button"
          variant={
            isPresetActive({
              $or: [{ opportunity_owner_id: identity?.id }, { account_manager_id: identity?.id }],
            })
              ? "default"
              : "outline"
          }
          size="sm"
          onClick={() =>
            handlePresetClick({
              $or: [{ opportunity_owner_id: identity?.id }, { account_manager_id: identity?.id }],
            })
          }
          className="w-full justify-start"
          title="Opportunities I manage"
        >
          <User className="w-3.5 h-3.5 mr-2" />
          My Opportunities
        </AdminButton>

        <AdminButton
          type="button"
          variant={
            isPresetActive({
              estimated_close_date_gte: today.toISOString().split("T")[0],
              estimated_close_date_lte: thirtyDaysFromNow.toISOString().split("T")[0],
            })
              ? "default"
              : "outline"
          }
          size="sm"
          onClick={() =>
            handlePresetClick({
              estimated_close_date_gte: today.toISOString().split("T")[0],
              estimated_close_date_lte: thirtyDaysFromNow.toISOString().split("T")[0],
            })
          }
          className="w-full justify-start"
          title="Opportunities with expected close date within 30 days"
        >
          <Calendar className="w-3.5 h-3.5 mr-2" />
          Closing This Month
        </AdminButton>

        <AdminButton
          type="button"
          variant={isPresetActive({ priority: ["high", "critical"] }) ? "default" : "outline"}
          size="sm"
          onClick={() => handlePresetClick({ priority: ["high", "critical"] })}
          className="w-full justify-start"
          title="Critical and high priority opportunities"
        >
          <AlertCircle className="w-3.5 h-3.5 mr-2" />
          High Priority
        </AdminButton>

        <AdminButton
          type="button"
          variant={
            isPresetActive({ next_action_date_lte: today.toISOString().split("T")[0] })
              ? "default"
              : "outline"
          }
          size="sm"
          onClick={() =>
            handlePresetClick({ next_action_date_lte: today.toISOString().split("T")[0] })
          }
          className="w-full justify-start"
          title="Opportunities with overdue or upcoming actions"
        >
          <Flag className="w-3.5 h-3.5 mr-2" />
          Needs Action
        </AdminButton>

        <AdminButton
          type="button"
          variant={
            isPresetActive({
              stage: STAGE.CLOSED_WON,
              updated_at_gte: addDays(today, -30).toISOString().split("T")[0],
            })
              ? "default"
              : "outline"
          }
          size="sm"
          onClick={() =>
            handlePresetClick({
              stage: STAGE.CLOSED_WON,
              updated_at_gte: addDays(today, -30).toISOString().split("T")[0],
            })
          }
          className="w-full justify-start"
          title="Opportunities closed won in the last 30 days"
        >
          <Trophy className="w-3.5 h-3.5 mr-2" />
          Recent Wins
        </AdminButton>
      </QuickFilterGroup>

      {/* Collapsible Filter Sections */}
      <FilterCategory label="Stage" icon={<Layers className="h-4 w-4" />}>
        {OPPORTUNITY_STAGES.map((stage) => (
          <ToggleFilterButton
            multiselect
            className="w-full justify-between"
            key={stage.value}
            label={stage.label}
            value={{ stage: stage.value }}
          />
        ))}
      </FilterCategory>

      <FilterCategory label="Priority" icon={<Flag className="h-4 w-4" />}>
        {priorityChoices.map((priority) => (
          <ToggleFilterButton
            multiselect
            className="w-full justify-between"
            key={priority.id}
            label={priority.name}
            value={{ priority: priority.id }}
          />
        ))}
      </FilterCategory>

      <FilterCategory label="Principal" icon={<Building2 className="h-4 w-4" />}>
        <Select value={currentPrincipalFilter} onValueChange={handlePrincipalChange}>
          <SelectTrigger
            className="w-full min-h-11 bg-background border-border text-foreground"
            aria-label="Filter by principal"
          >
            <SelectValue placeholder="All Principals" />
          </SelectTrigger>
          <SelectContent className="max-h-60">
            <SelectItem value="all" className="min-h-11">
              <span className="text-muted-foreground">All Principals</span>
            </SelectItem>
            {principalsData?.map((org) => (
              <SelectItem key={org.id} value={String(org.id)} className="min-h-11">
                <span className="truncate" title={org.name}>
                  {org.name}
                </span>
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </FilterCategory>

      <FilterCategory label="Customer" icon={<Building2 className="h-4 w-4" />}>
        <Select value={currentCustomerFilter} onValueChange={handleCustomerChange}>
          <SelectTrigger
            className="w-full min-h-11 bg-background border-border text-foreground"
            aria-label="Filter by customer"
          >
            <SelectValue placeholder="All Customers" />
          </SelectTrigger>
          <SelectContent className="max-h-60">
            <SelectItem value="all" className="min-h-11">
              <span className="text-muted-foreground">All Customers</span>
            </SelectItem>
            {customersData?.map((org) => (
              <SelectItem key={org.id} value={String(org.id)} className="min-h-11">
                <span className="truncate" title={org.name}>
                  {org.name}
                </span>
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </FilterCategory>

      <FilterCategory label="Campaign" icon={<Megaphone className="h-4 w-4" />}>
        <Select value={currentCampaignFilter} onValueChange={handleCampaignChange}>
          <SelectTrigger
            className="w-full min-h-11 bg-background border-border text-foreground"
            aria-label="Filter by campaign"
          >
            <SelectValue placeholder="All Campaigns" />
          </SelectTrigger>
          <SelectContent className="max-h-60">
            <SelectItem value="all" className="min-h-11">
              <span className="text-muted-foreground">All Campaigns</span>
            </SelectItem>
            {campaigns.map((campaign) => (
              <SelectItem key={campaign} value={campaign} className="min-h-11">
                <span className="truncate" title={campaign}>
                  {campaign}
                </span>
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </FilterCategory>

      <OwnerFilterDropdown
        source="opportunity_owner_id"
        secondarySource="account_manager_id"
        label="Owner"
      />
    </FilterSidebar>
  );
};
